(function(w){"use strict";
function e(v){return String(v==null?"":v).replace(/[&<>\"]/g,function(c){return {"&":"&amp;","<":"&lt;",">":"&gt;","\"":"&quot;"}[c]||c;});}
function renderField(f){var a=' data-key="'+e(f.key)+'"';if(f.raw)a+=' data-raw="1"';if(f.type==='select'){return '<div class="hm-calc-field"><label>'+e(f.label)+'</label><select class="hm-calc-select"'+a+'>'+f.options.map(function(o){return '<option value="'+e(o[0])+'"'+(String(o[0])===String(f.default)?' selected':'')+'>'+e(o[1])+'</option>';}).join('')+'</select></div>';}if(f.type==='textarea'){return '<div class="hm-calc-field"><label>'+e(f.label)+'</label><textarea class="hm-calc-input" rows="4"'+a+' placeholder="'+e(f.placeholder||'')+'">'+e(f.default||'')+'</textarea></div>';}var type=f.type==='date'?'date':'text';var mode=f.type==='integer'?'numeric':'decimal';return '<div class="hm-calc-field"><label>'+e(f.label)+'</label><input class="hm-calc-input" type="'+type+'" inputmode="'+mode+'"'+a+' placeholder="'+e(f.placeholder||'')+'" value="'+e(f.default||'')+'"></div>';}
function makeRender(def){return function(root,api){var html='<div class="hm-calc-panel"><div class="hm-calc-form">';if(def.hint)html+='<p class="hm-calc-hint">'+e(def.hint)+'</p>';html+='<div class="hm-calc-grid-2">'+def.fields.map(renderField).join('')+'</div><div class="hm-calc-actions"><button type="button" class="hm-calc-btn">계산하기</button></div><p class="hm-calc-message" hidden></p></div><div class="hm-calc-result" hidden></div></div>';root.innerHTML=html;var els=Array.prototype.slice.call(root.querySelectorAll('[data-key]')),go=root.querySelector('button'),msg=root.querySelector('.hm-calc-message'),res=root.querySelector('.hm-calc-result');go.addEventListener('click',function(){var x={};els.forEach(function(el){var k=el.getAttribute('data-key');if(el.tagName==='SELECT'||el.getAttribute('data-raw')==='1'||el.type==='date')x[k]=el.value;else x[k]=api.parseNumber(el.value);});var r=def.compute(x);if(r&&r.error){api.setMessage(msg,r.error);api.clearResult(res);return;}api.setMessage(msg,'');api.setResult(res,def.format(r,api));});};}
var defs=[{id:"floor-area-ratio",fields:[{"key":"landArea","label":"대지면적 (㎡)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"floorArea","label":"용적률 산정 연면적 (㎡)","type":"number","placeholder":"","default":"","options":[],"raw":false}],hint:"법령상 산정 제외면적 등은 반영하지 않은 단순 계산입니다.",compute:function(x){var l=Number(x.landArea),f=Number(x.floorArea);if(![l,f].every(Number.isFinite)||l<=0||f<0)return{error:"대지면적은 0보다 크게, 연면적은 0 이상으로 입력해 주세요."};return{far:f/l*100,landArea:l,floorArea:f};},format:function(r,api){return api.resultCard("용적률",api.formatNumber(r.far,2)+"%","연면적 "+api.formatNumber(r.floorArea,2)+"㎡");}},{id:"building-coverage-ratio",fields:[{"key":"landArea","label":"대지면적 (㎡)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"buildingArea","label":"건축면적 (㎡)","type":"number","placeholder":"","default":"","options":[],"raw":false}],hint:"법령상 건축면적 산정기준은 별도로 확인해야 합니다.",compute:function(x){var l=Number(x.landArea),b=Number(x.buildingArea);if(![l,b].every(Number.isFinite)||l<=0||b<0)return{error:"대지면적은 0보다 크게, 건축면적은 0 이상으로 입력해 주세요."};return{coverage:b/l*100,remainingLand:l-b,buildingArea:b};},format:function(r,api){return api.resultCard("건폐율",api.formatNumber(r.coverage,2)+"%","")+api.resultCard("비건축 면적",api.formatNumber(r.remainingLand,2)+"㎡","");}},{id:"land-share-per-unit",fields:[{"key":"totalLandArea","label":"전체 대지면적 (㎡)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"units","label":"전체 세대 수","type":"integer","placeholder":"","default":"","options":[],"raw":false}],hint:"실제 등기 대지권 비율은 세대별로 다를 수 있습니다.",compute:function(x){var a=Number(x.totalLandArea),u=Number(x.units);if(![a,u].every(Number.isFinite)||a<=0||!Number.isInteger(u)||u<=0)return{error:"대지면적은 0보다 크게, 세대 수는 0보다 큰 정수로 입력해 주세요."};var sqm=a/u;return{shareSqm:sqm,sharePyeong:sqm/3.305785,totalLandArea:a};},format:function(r,api){return api.resultCard("세대당 평균 대지지분",api.formatNumber(r.shareSqm,3)+"㎡",api.formatNumber(r.sharePyeong,3)+"평");}},{id:"rent-per-pyeong",fields:[{"key":"monthlyRent","label":"월세","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"areaSqm","label":"전용면적 (㎡)","type":"number","placeholder":"","default":"","options":[],"raw":false}],hint:"",compute:function(x){var r=Number(x.monthlyRent),a=Number(x.areaSqm);if(![r,a].every(Number.isFinite)||r<0||a<=0)return{error:"월세는 0 이상, 면적은 0보다 크게 입력해 주세요."};var p=a/3.305785;return{areaPyeong:p,rentPerPyeong:r/p,rentPerSqm:r/a};},format:function(r,api){return api.resultCard("평당 월세",api.formatMoney(r.rentPerPyeong),api.formatNumber(r.areaPyeong,2)+"평 기준")+api.resultCard("㎡당 월세",api.formatMoney(r.rentPerSqm),"");}},{id:"noi-cap-rate",fields:[{"key":"annualGrossIncome","label":"연간 잠재 임대수입","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"vacancyLoss","label":"연간 공실·미수 손실","type":"number","placeholder":"","default":"0","options":[],"raw":false},{"key":"operatingExpenses","label":"연간 운영비","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"propertyValue","label":"부동산 가치","type":"number","placeholder":"","default":"","options":[],"raw":false}],hint:"대출 원리금과 세금은 운영비 포함 여부에 따라 별도 조정하세요.",compute:function(x){var g=Number(x.annualGrossIncome),v=Number(x.vacancyLoss),e=Number(x.operatingExpenses),p=Number(x.propertyValue);if(![g,v,e,p].every(Number.isFinite)||g<0||v<0||e<0||p<=0||v>g)return{error:"수입·손실·운영비는 0 이상, 부동산 가치는 0보다 크게 입력해 주세요."};var noi=g-v-e;return{effectiveIncome:g-v,noi:noi,capRate:noi/p*100};},format:function(r,api){return api.resultCard("순영업소득 NOI",api.formatMoney(r.noi),"유효총수입 "+api.formatMoney(r.effectiveIncome))+api.resultCard("캡레이트",api.formatNumber(r.capRate,2)+"%","");}},{id:"break-even-occupancy",fields:[{"key":"grossPotentialIncome","label":"100% 점유 시 연간 수입","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"operatingExpenses","label":"연간 운영비","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"debtService","label":"연간 대출 원리금","type":"number","placeholder":"","default":"0","options":[],"raw":false}],hint:"",compute:function(x){var g=Number(x.grossPotentialIncome),e=Number(x.operatingExpenses),d=Number(x.debtService);if(![g,e,d].every(Number.isFinite)||g<=0||e<0||d<0)return{error:"잠재수입은 0보다 크게, 비용은 0 이상으로 입력해 주세요."};var rate=(e+d)/g*100;return{breakEvenOccupancy:rate,breakEvenVacancy:100-rate,requiredIncome:e+d};},format:function(r,api){return api.resultCard("손익분기 점유율",api.formatNumber(r.breakEvenOccupancy,2)+"%","필요수입 "+api.formatMoney(r.requiredIncome))+api.resultCard("허용 공실률",api.formatNumber(r.breakEvenVacancy,2)+"%","");}}];defs.forEach(function(def){w.HM_CALC.register(def.id,{compute:def.compute,render:makeRender(def)});});})(window);
